#!/usr/bin/env python3
from plugins.common.plugin_entry import nv_enrich_plugin
from plugins.common.plugin_utils import load_detection_crop
from plugins.common.color_utils import dominant_color_name_from_crop

@nv_enrich_plugin("color_basic", result_scope="detection")
def process_job(job):
    detection = job.get("detection")
    frame = job.get("frame")

    if not detection or not frame:
        return {"color": "unknown", "confidence": 0.0}

    crop = load_detection_crop(frame, detection)
    if crop is None:
        return {"color": "unknown", "confidence": 0.0}

    color_name, conf, extras = dominant_color_name_from_crop(crop)
    return {
        "descriptors": {
            "color": color_name,
            "confidence": conf
        },
        "metadata": {
            "extras": extras
        }
    }
